CREATE OR REPLACE FUNCTION fpb_kep_count_mem ( ai_year bigint , ai_month bigint , as_method char ,as_bgroup char ,as_egroup char ) RETURNS integer AS $body$
DECLARE

li_count integer;


BEGIN

   SELECT COUNT( DISTINCT sc_mem_m_membership_registered.membership_no )
   INTO STRICT li_count
   FROM sc_kep_t_monthly_receive_det,
		sc_kep_m_ucf_keeping_item_type,
		sc_mem_m_membership_registered,
		sc_mem_m_ucf_member_group,
		sc_kep_t_monthly_receive  ,
		sc_acc_m_account_master
   WHERE ( sc_kep_t_monthly_receive_det.keeping_type_code = sc_kep_m_ucf_keeping_item_type.keeping_type_code ) and ( sc_kep_t_monthly_receive_det.membership_no = sc_mem_m_membership_registered.membership_no ) and ( sc_mem_m_membership_registered.member_group_no = sc_mem_m_ucf_member_group.member_group_no ) and ( sc_kep_t_monthly_receive.membership_no = sc_kep_t_monthly_receive_det.membership_no ) and ( sc_kep_t_monthly_receive.receive_year = sc_kep_t_monthly_receive_det.receive_year ) and ( sc_kep_t_monthly_receive.receive_month = sc_kep_t_monthly_receive_det.receive_month ) and ( sc_kep_t_monthly_receive.seq_no = sc_kep_t_monthly_receive_det.seq_no ) and ( sc_kep_m_ucf_keeping_item_type.account_id = sc_acc_m_account_master.account_id ) and ( sc_kep_t_monthly_receive_det.receive_year = ai_year ) AND ( sc_kep_t_monthly_receive_det.receive_month = ai_month ) AND ( sc_kep_t_monthly_receive.kep_method = as_method ) AND ( sc_mem_m_ucf_member_group.member_group_no between as_bgroup and as_egroup )
;
  if coalesce(li_count::text, '') = ''  then li_count :=0;end if;
  RETURN li_count;
END;
